  1â†’#!/usr/bin/env bun
  2â†’
  3â†’/**
  4â†’ * Ralph Loop - Automated Claude Code Task Executor
  5â†’ *
  6â†’ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7â†’ * - Fresh context per iteration (new Claude instance each time)
  8â†’ * - Memory persists through files only (git, progress.txt)
  9â†’ * - One task per iteration
 10â†’ * - Completion signal terminates loop
 11â†’ *
 12â†’ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13â†’ *
 14â†’ * @see https://ghuntley.com/ralph/
 15â†’ */
 16â†’
 17â†’import { appendFileSync, mkdirSync, renameSync } from 'node:fs';
 18â†’import { chalk } from 'zx';
 19â†’import {
 20â†’  AsyncSeriesHook,
 21â†’  SyncHook,
 22â†’  SyncWaterfallHook,
 23â†’  SyncBailHook,
 24â†’} from 'tapable';
 25â†’
 26â†’const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 27â†’const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 28â†’
 29â†’function parsePositiveInt(arg: string | undefined, fallback: number): number {
 30â†’  const parsed = parseInt(arg ?? String(fallback), 10);
 31â†’  if (isNaN(parsed) || parsed <= 0) {
 32â†’    console.error(`Error: expected a positive integer, got "${arg}"`);
 33â†’    process.exit(1);
 34â†’  }
 35â†’  return parsed;
 36â†’}
 37â†’
 38â†’const LOG_DIR = './.loop';
 39â†’mkdirSync(LOG_DIR, { recursive: true });
 40â†’
 41â†’const CONFIG = Object.freeze({
 42â†’  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 43â†’  delayBetweenIterations: 1_000,
 44â†’  progressFile: './.claude/progress.txt',
 45â†’  iterationTimeout: 600_000,
 46â†’  logFlushInterval: 2_000,
 47â†’  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 48â†’});
 49â†’
 50â†’interface IterationContext {
 51â†’  iteration: number;
 52â†’  maxIterations: number;
 53â†’  logPath: string;
 54â†’}
 55â†’
 56â†’interface FailureContext extends IterationContext {
 57â†’  exitCode: number;
 58â†’  consecutiveFailures: number;
 59â†’}
 60â†’
 61â†’interface BackoffContext extends FailureContext {
 62â†’  backoffMs: number;
 63â†’}
 64â†’
 65â†’const hooks = {
 66â†’  loopStart: new AsyncSeriesHook<[typeof CONFIG]>(['config']),
 67â†’  iterationStart: new AsyncSeriesHook<[IterationContext]>(['context']),
 68â†’  iterationSuccess: new AsyncSeriesHook<[IterationResult, IterationContext]>([
 69â†’    'result',
 70â†’    'context',
 71â†’  ]),
 72â†’  iterationTimeout: new SyncHook<[IterationResult, IterationContext]>([
 73â†’    'result',
 74â†’    'context',
 75â†’  ]),
 76â†’  iterationFailure: new AsyncSeriesHook<[IterationResult, FailureContext]>([
 77â†’    'result',
 78â†’    'context',
 79â†’  ]),
 80â†’  statusParsed: new SyncWaterfallHook<[RalphStatus | null, string]>([
 81â†’    'status',
 82â†’    'output',
 83â†’  ]),
 84â†’  taskComplete: new AsyncSeriesHook<[RalphStatus, IterationContext]>([
 85â†’    'status',
 86â†’    'context',
 87â†’  ]),
 88â†’  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
 89â†’    'status',
 90â†’    'totalIterations',
 91â†’  ]),
 92â†’  backoff: new SyncBailHook<[BackoffContext], boolean>(['context']),
 93â†’  loopEnd: new SyncHook<[number]>(['totalIterations']),
 94â†’  cleanup: new SyncHook<[string]>(['signal']),
 95â†’};
 96â†’
 97â†’export { hooks as ralphHooks };
