 99â†’function slugify(text: string): string {
100â†’  return text
101â†’    .toLowerCase()
102â†’    .normalize('NFD')
103â†’    .replace(/[\u0300-\u036f]/g, '')
104â†’    .replace(/[^a-z0-9]+/g, '-')
105â†’    .replace(/^-+|-+$/g, '')
106â†’    .slice(0, 60);
107â†’}
