109â†’function logTimestamp(): string {
110â†’  const d = new Date();
111â†’  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
112â†’}
113â†’
114â†’function logFilePath(slug: string): string {
115â†’  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
116â†’}
