118â†’class LogBuffer {
119â†’  private buf: string[] = [];
120â†’  private timer: ReturnType<typeof setInterval> | null = null;
121â†’  private path: string;
122â†’
123â†’  constructor(
124â†’    initialPath: string,
125â†’    private readonly flushMs: number,
126â†’  ) {
127â†’    this.path = initialPath;
128â†’    this.timer = setInterval(() => this.flush(), this.flushMs);
129â†’    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
130â†’      (this.timer as NodeJS.Timeout).unref();
131â†’    }
132â†’  }
133â†’
134â†’  write(raw: string): void {
135â†’    this.buf.push(stripAnsi(raw));
136â†’  }
137â†’
138â†’  flush(): void {
139â†’    if (this.buf.length === 0) return;
140â†’    const chunk = this.buf.join('');
141â†’    this.buf.length = 0;
142â†’    try {
143â†’      appendFileSync(this.path, chunk);
144â†’    } catch (err) {
145â†’      console.error(`[LogBuffer] write failed: ${err}`);
146â†’    }
147â†’  }
148â†’
149â†’  startNewFile(newPath: string): void {
150â†’    this.flush();
151â†’    this.path = newPath;
152â†’  }
153â†’
154â†’  renameFile(newPath: string): void {
155â†’    this.flush();
156â†’    try {
157â†’      renameSync(this.path, newPath);
158â†’      this.path = newPath;
159â†’    } catch {}
160â†’  }
161â†’
162â†’  currentPath(): string {
163â†’    return this.path;
164â†’  }
165â†’
166â†’  dispose(): void {
167â†’    if (this.timer) clearInterval(this.timer);
168â†’    this.flush();
169â†’  }
170â†’}
171â†’
172â†’const logBuffer = new LogBuffer(
173â†’  logFilePath('startup'),
174â†’  CONFIG.logFlushInterval,
175â†’);
