177â†’type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
178â†’
179â†’function print(message: string, color?: Color): void {
180â†’  const colored = color ? chalk[color](message) : message;
181â†’  process.stdout.write(colored);
182â†’  logBuffer.write(message);
183â†’}
