252â†’interface ContentBlock {
253â†’  type: 'text' | 'tool_use' | 'tool_result';
254â†’  text?: string;
255â†’  name?: string;
256â†’  input?: unknown;
257â†’  content?:
258â†’    | string
259â†’    | Array<{
260â†’        type: string;
261â†’        text?: string;
262â†’      }>;
263â†’}
264â†’
265â†’interface StreamMessage {
266â†’  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
267â†’  subtype?: string;
268â†’  role?: 'assistant' | 'user';
269â†’  event?: {
270â†’    type: string;
271â†’    delta?: {
272â†’      type: string;
273â†’      text?: string;
274â†’    };
275â†’  };
276â†’  result?: string;
277â†’  message?: {
278â†’    role?: string;
279â†’    content?: ContentBlock[];
280â†’  };
281â†’  content?: ContentBlock[];
282â†’}
283â†’
284â†’interface RalphStatus {
285â†’  exit: boolean;
286â†’  task: string;
287â†’  remaining: number;
288â†’}
289â†’
290â†’function parseRalphStatus(output: string): RalphStatus | null {
291â†’  const marker = output.lastIndexOf('RALPH_STATUS:');
292â†’  if (marker === -1) return null;
293â†’
294â†’  const jsonStart = output.indexOf('{', marker);
295â†’  if (jsonStart === -1) return null;
296â†’
297â†’  let depth = 0;
298â†’  for (let i = jsonStart; i < output.length; i++) {
299â†’    if (output[i] === '{') depth++;
300â†’    if (output[i] === '}') depth--;
301â†’    if (depth === 0) {
302â†’      try {
303â†’        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
304â†’        if (typeof parsed.exit === 'boolean') {
305â†’          return parsed as RalphStatus;
306â†’        }
307â†’      } catch {}
308â†’      return null;
309â†’    }
310â†’  }
311â†’  return null;
312â†’}
