314â†’let currentProc: ReturnType<typeof Bun.spawn> | null = null;
315â†’
316â†’function killCurrentProc(): void {
317â†’  if (!currentProc) return;
318â†’  try {
319â†’    currentProc.kill();
320â†’  } catch {}
321â†’}
