323â†’async function checkDependencies(): Promise<void> {
324â†’  const result = await Bun.$`which claude`.quiet().nothrow();
325â†’  if (result.exitCode !== 0) {
326â†’    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
327â†’    process.exit(1);
328â†’  }
329â†’
330â†’  if (!(await Bun.file(CONFIG.progressFile).exists())) {
331â†’    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
332â†’    process.exit(1);
333â†’  }
334â†’}
