336â†’interface IterationResult {
337â†’  output: string;
338â†’  exitCode: number;
339â†’  timedOut: boolean;
340â†’}
341â†’
342â†’async function runIteration(): Promise<IterationResult> {
343â†’  syslog('Executing Claude Code...');
344â†’
345â†’  const proc = Bun.spawn(
346â†’    [
347â†’      'claude',
348â†’      '-p',
349â†’      TASK_PROMPT,
350â†’      '--verbose',
351â†’      '--debug',
352â†’      '--dangerously-skip-permissions',
353â†’      '--output-format',
354â†’      'stream-json',
355â†’      '--include-partial-messages',
356â†’      '--model=opus',
357â†’    ],
358â†’    {
359â†’      cwd: process.cwd(),
360â†’      env: process.env,
361â†’      stdout: 'pipe',
362â†’      stderr: 'inherit',
363â†’    },
364â†’  );
365â†’
366â†’  currentProc = proc;
367â†’
368â†’  const chunks: string[] = [];
369â†’  let timedOut = false;
370â†’  const decoder = new TextDecoder();
371â†’  let buffer = '';
372â†’  let blockHasContent = false;
373â†’
374â†’  const timeoutId = setTimeout(() => {
375â†’    timedOut = true;
376â†’    syslog('Iteration timeout reached. Killing process...', 'yellow');
377â†’    killCurrentProc();
378â†’  }, CONFIG.iterationTimeout);
379â†’
380â†’  const reader = proc.stdout.getReader();
381â†’
382â†’  try {
383â†’    while (true) {
384â†’      const { done, value } = await reader.read();
385â†’      if (done) break;
386â†’
387â†’      buffer += decoder.decode(value, { stream: true });
388â†’
389â†’      const lines = buffer.split('\n');
390â†’      buffer = lines.pop() || '';
391â†’
392â†’      for (const line of lines) {
393â†’        if (!line.trim()) continue;
394â†’
395â†’        let msg: StreamMessage;
396â†’        try {
397â†’          msg = JSON.parse(line);
398â†’        } catch {
399â†’          continue;
400â†’        }
401â†’
402â†’        if (msg.type === 'stream_event') {
403â†’          const evt = msg.event;
404â†’          if (!evt) continue;
405â†’
406â†’          if (evt.type === 'content_block_start') {
407â†’            blockHasContent = false;
408â†’          } else if (evt.type === 'content_block_delta') {
409â†’            const text = evt.delta?.text;
410â†’            if (text) {
411â†’              print(text);
412â†’              chunks.push(text);
413â†’              blockHasContent = true;
414â†’            }
415â†’          } else if (evt.type === 'content_block_stop' && blockHasContent) {
416â†’            print('\n');
417â†’            chunks.push('\n');
418â†’            blockHasContent = false;
419â†’          }
420â†’          continue;
421â†’        }
422â†’
423â†’        if (msg.type === 'assistant' || msg.type === 'message') {
424â†’          // Content already streamed via content_block_delta events.
425â†’          // Only print here as fallback if no streaming occurred.
426â†’          const blocks = msg.message?.content ?? msg.content;
427â†’          if (!Array.isArray(blocks)) continue;
428â†’
429â†’          for (const block of blocks) {
430â†’            if (block.type === 'text' && block.text && chunks.length === 0) {
431â†’              print(block.text);
432â†’              chunks.push(block.text);
433â†’              print('\n');
434â†’              chunks.push('\n');
435â†’            }
436â†’          }
437â†’          continue;
438â†’        }
439â†’
440â†’        if (msg.type === 'user') {
441â†’          const blocks = msg.message?.content ?? msg.content;
442â†’          if (!Array.isArray(blocks)) continue;
443â†’
444â†’          for (const block of blocks) {
445â†’            //
446â†’            // Handling tool result
447â†’            if (block.type === 'tool_result' && block.content) {
448â†’              const rawContent =
449â†’                typeof block.content === 'string'
450â†’                  ? block.content
451â†’                  : block.content
452â†’                      .map(c => c.text ?? '')
453â†’                      .filter(Boolean)
454â†’                      .join('\n');
455â†’
456â†’              if (!rawContent) continue;
457â†’
458â†’              let trimmed = rawContent.trim().slice(0, 320);
459â†’
460â†’              const toolResult =
461â†’                trimmed && trimmed !== rawContent
462â†’                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
463â†’                  : rawContent;
464â†’
465â†’              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
466â†’              chunks.push('\n', rawContent, '\n');
467â†’            }
468â†’          }
469â†’          continue;
470â†’        }
471â†’
472â†’        if (msg.type === 'result' && msg.result) {
473â†’          if (chunks.length === 0) {
474â†’            chunks.push(msg.result);
475â†’          }
476â†’        }
477â†’      }
478â†’    }
479â†’
480â†’    if (buffer.trim()) {
481â†’      try {
482â†’        const msg: StreamMessage = JSON.parse(buffer);
483â†’        if (msg.type === 'result' && msg.result && chunks.length === 0) {
484â†’          chunks.push(msg.result);
485â†’        }
486â†’      } catch {}
487â†’    }
488â†’  } finally {
489â†’    clearTimeout(timeoutId);
490â†’    reader.releaseLock();
491â†’    currentProc = null;
492â†’    logBuffer.flush();
493â†’  }
494â†’
495â†’  const output = chunks.join('');
496â†’
497â†’  if (timedOut) {
498â†’    return {
499â†’      output,
500â†’      exitCode: 124,
501â†’      timedOut: true,
502â†’    };
503â†’  }
504â†’
505â†’  const exitCode = await proc.exited;
506â†’  println();
507â†’  return {
508â†’    output,
509â†’    exitCode,
510â†’    timedOut: false,
511â†’  };
512â†’}
