514â†’function printHeader(): void {
515â†’  println();
516â†’  println('==========================================', 'blue');
517â†’  println('   Ralph Loop - Bun.js Edition', 'blue');
518â†’  println('==========================================', 'blue');
519â†’  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
520â†’  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
521â†’  println(
522â†’    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
523â†’  );
524â†’  println(
