530â†’async function main(): Promise<void> {
531â†’  let cleanupCalled = false;
532â†’
533â†’  const cleanup = (signal: string) => {
534â†’    if (cleanupCalled) return;
535â†’    cleanupCalled = true;
536â†’    hooks.cleanup.call(signal);
537â†’    println();
538â†’    syslog(`Interrupted by ${signal}. Cleaning up...`);
539â†’    killCurrentProc();
540â†’    logBuffer.dispose();
541â†’    process.exit(signal === 'SIGINT' ? 130 : 143);
542â†’  };
543â†’
544â†’  process.on('SIGINT', () => cleanup('SIGINT'));
545â†’  process.on('SIGTERM', () => cleanup('SIGTERM'));
546â†’
547â†’  await checkDependencies();
548â†’
549â†’  printHeader();
550â†’  syslog('Starting automated task loop...');
551â†’
552â†’  await hooks.loopStart.promise(CONFIG);
553â†’
554â†’  let consecutiveFailures = 0;
555â†’  let iteration = 0;
556â†’  const BACKOFF_BASE_MS = 60_000;
557â†’  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
558â†’
559â†’  while (iteration < CONFIG.maxIterations) {
560â†’    const attemptNum = iteration + 1;
561â†’    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
562â†’
563â†’    const iterCtx: IterationContext = {
564â†’      iteration: attemptNum,
565â†’      maxIterations: CONFIG.maxIterations,
566â†’      logPath: logBuffer.currentPath(),
567â†’    };
568â†’
569â†’    println();
570â†’    println('==========================================', 'green');
571â†’    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
572â†’    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
573â†’    println('==========================================', 'green');
574â†’    println();
575â†’
576â†’    await hooks.iterationStart.promise(iterCtx);
577â†’
578â†’    const result = await runIteration();
579â†’    const { output, exitCode, timedOut } = result;
580â†’
581â†’    if (exitCode === 0) {
582â†’      syslog('Claude Code completed successfully', 'green');
583â†’      consecutiveFailures = 0;
584â†’      await hooks.iterationSuccess.promise(result, iterCtx);
585â†’    } else if (timedOut) {
586â†’      syslog(
587â†’        'Iteration timed out â€” progress may persist in progress.txt',
588â†’        'yellow',
589â†’      );
590â†’      consecutiveFailures = 0;
591â†’      hooks.iterationTimeout.call(result, iterCtx);
592â†’    } else {
593â†’      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
594â†’      consecutiveFailures++;
595â†’
596â†’      const failCtx: FailureContext = {
597â†’        ...iterCtx,
598â†’        exitCode,
599â†’        consecutiveFailures,
600â†’      };
601â†’      await hooks.iterationFailure.promise(result, failCtx);
602â†’
